document.addEventListener("DOMContentLoaded",function(){var e=document.getElementsByTagName("sidenav");if(0!==e.length){var t=e[0].getElementsByTagName("drawer")[0];document.querySelectorAll('[data-target="slide-out"]').forEach(function(e){e.addEventListener("click",function(){var e="false"!==t.getAttribute("aria-hidden");t.setAttribute("aria-hidden",e?"false":"true")})})}});